parameters.text:
=Analyse this information and return the diagnostic JSON following the given schema:

{
  "url": "{{ $json.url }}",
  "page_title": "{{ $json.pageTitle }}",
  "text": "{{ $json.text }}",
  "signals": {{ JSON.stringify($json.signals) }}
}

=Write the email for this diagnostic:
{{ JSON.stringify($json.output) }}

Optional parameters:
{
  "channel": "email",
  "length": "standard",
  "style": "direct",
  "language": "{{ $json.output.diagnostic.meta.lang_detected || 'en' }}"
}

parameters.jsCode:
const html = $input.first().json.data || '';
const cleaned = html
  .replace(/<script[\s\S]*?<\/script>/gi,' ')
  .replace(/<style[\s\S]*?<\/style>/gi,' ')
  .replace(/<!--[\s\S]*?-->/g,' ')
  .replace(/<[^>]+>/g,' ')
  .replace(/\s+/g,' ')
  .trim();

const text = cleaned.slice(0, 28000); // hard limit ~6-8k tokens
const signals = {
  url: $json.url || '',
  page_title: $json.pageTitle || '',
  has_wa: /wa\.me|api\.whatsapp\.com/i.test(html),
  has_tel: /tel:/i.test(html),
  has_mailto: /mailto:/i.test(html),
  has_checkout: /checkout|cart|add to cart|woocommerce/i.test(html),
  has_booking: /calendly|book now|appointment|booking|schedule/i.test(html),
  social: [...new Set((html.match(/instagram\.com|linkedin\.com|facebook\.com|youtube\.com/gi) || []).map(s => s.toLowerCase()))]
};

return [{ url: signals.url, pageTitle: signals.page_title, text, signals }];
